            'en', jsonb_build_object('name','Barbell Bench Press','description','The foundational chest exercise performed on a flat bench with a barbell. Grip the bar slightly wider than shoulder-width, lower it under control to mid-chest, and press explosively back to the start. Keep scapulae retracted, feet flat on the floor, and maintain a neutral spine to maximize force transfer and minimize injury risk.')
        ),
        NOW(), NOW()
    );

