            jsonb_build_object('it',jsonb_build_object('name','Panca da Gara','description','Tecnica di panca eseguita secondo le regole federali del powerlifting: arco lombare marcato, piedi piatti, pausa obbligatoria sul petto e pressione sul segnale del giudice. Ottimizzata per massimizzare il carico sollevato.'),'en',jsonb_build_object('name','Competition Bench Press','description','Bench press performed according to powerlifting federation rules: pronounced arch, flat feet, mandatory pause on chest, and press on judges command. Technique optimized to maximize the weight lifted.')),NOW(),NOW());
